#include <stdio.h>
#include <string.h>
int main(){
	int i,j,len;
	char mayor;
	char string[11];
	char res[11]={'\0'};

	scanf("%s" , string);

	len = strlen(string);
	mayor = string[0];

	for( i = 1 ; i < len; i++ ){
		if( string[i] > mayor ){
			mayor = string[i];
		}
	}

	for( i = 0 ; i < len; i++ ){

		if( string[i] == mayor ){

			j = 0;

			while( res[j] != '\0' ){
				j++;
			}

			res[j] = string[i];
			res[j+1] = '\0';
		}
	}


	printf( "%s" , res );
	return 0;
}

