use std::io::{self, BufRead};

fn main() {
    let stdin = io::stdin();
    let mut input = String::new();

    stdin.lock().read_line(&mut input).unwrap();

    let seq = input.trim().as_bytes();

    let n = seq.len();
    let mut largest = seq.to_vec();
    for i in 1..2usize.pow(n as u32) {
        let mut subseq = Vec::with_capacity(n);
        for k in 0..n {
            if i >> k & 1 == 1 {
                subseq.push(seq[k])
            }
        }
        if !is_palindrome(&subseq) {
            continue;
        }
        if is_lexicographically_larger(&subseq, &largest) {
            largest = subseq;
        }
    }
    println!("{}", String::from_utf8_lossy(&largest));
}

fn is_palindrome(seq: &[u8]) -> bool{
    for i in 0..seq.len()/2 {
        if seq[i] != seq[seq.len()-i-1] {
            return false;
        }
    }

    true
}

fn is_lexicographically_larger(a: &[u8], b: &[u8]) -> bool {
    let mut i = 0;
    let mut same = true;

    while i < a.len() && i < b.len() {
        if same {
            if a[i] != b[i] {
                same = false;
            }
        }

        if !same {
            if a[i] <= b[i] {
                return false;
            }
        }
        i += 1;
    }
    true
}
